from typing import List

class Solution:
    def validStrings(self, n: int) -> List[str]:
        # Base cases
        if n == 1:
            return ["0", "1"]

        # DP table: dp[i][j] stores all valid strings of length i ending with j (0 or 1)
        dp = [{} for _ in range(n)]

        # Initialize for length 1
        dp[0][0] = ["0"]
        dp[0][1] = ["1"]

        # Fill DP table
        for i in range(1, n):
            # For ending with 0, previous string must end with 1
            if 1 in dp[i - 1]:
                dp[i][0] = [s + "0" for s in dp[i - 1][1]]
            # For ending with 1, previous string can end with 0 or 1
            if 0 in dp[i - 1]:
                dp[i][1] = [s + "1" for s in dp[i - 1][0]]
            if 1 in dp[i - 1]:
                dp[i][1].extend([s + "1" for s in dp[i - 1][1]])

        # Combine all valid strings of length n
        result = []
        if 0 in dp[n - 1]:
            result.extend(dp[n - 1][0])
        if 1 in dp[n - 1]:
            result.extend(dp[n - 1][1])

        return result
